  1	import * as React from 'react';
  2	import { MultiSelectDropdown } from '@odf/shared';
  3	import { useDeepCompareMemoize } from '@odf/shared/hooks/deep-compare-memoize';
  4	import { getName, getUID } from '@odf/shared/selectors';
  5	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  6	import { TFunction } from 'react-i18next';
  7	import { SelectOption } from '@patternfly/react-core';
  8	import { HelperText, HelperTextItem } from '@patternfly/react-core';
  9	import { checkDRActionReadiness } from '../../../../utils';
 10	import { ErrorMessageType } from './error-messages';
 11	import { PlacementDecision } from './reducer';
 12	import {
 13	  FailoverAndRelocateState,
 14	  FailoverAndRelocateAction,
 15	  DRPolicyControlState,
 16	  FailoverAndRelocateType,
 17	  ModalFooterStatus,
 18	} from './reducer';
 19	
 20	const validateDRPolicy = (
 21	  drPolicyControlState: DRPolicyControlState,
 22	  drPolicyName: string
 23	) =>
 24	  drPolicyControlState.drPlacementControl?.spec?.drPolicyRef?.name ===
 25	  drPolicyName;
 26	
 27	const validateTargetCluster = (
 28	  drPolicyControlState: DRPolicyControlState,
 29	  targetCluster: PlacementDecision
 30	) => {
 31	  const currentDeploymentCluster = drPolicyControlState?.clusterName;
 32	  return (
 33	    currentDeploymentCluster !== targetCluster?.clusterName &&
 34	    currentDeploymentCluster !== targetCluster?.clusterNamespace
 35	  );
 36	};
 37	
 38	const getValidOptions = (
 39	  option: React.ReactElement,
 40	  validOptions: React.ReactElement[],
 41	  isValidTargetCluster: boolean,
 42	  isDRReady: boolean
 43	) =>
 44	  isValidTargetCluster
 45	    ? isDRReady
 46	      ? [option, ...validOptions]
 47	      : [...validOptions, option]
 48	    : validOptions;
 49	
 50	const getInValidOptions = (
 51	  option: React.ReactElement,
 52	  inValidOptions: React.ReactElement[],
 53	  isValidTargetCluster: boolean
 54	) => (isValidTargetCluster ? inValidOptions : [option, ...inValidOptions]);
 55	
 56	const getOptions = (
 57	  drPolicyControlState: DRPolicyControlState,
 58	  isValid: boolean,
 59	  t: TFunction
 60	) => (
 61	  <SelectOption
 62	    key={getUID(drPolicyControlState?.drPlacementControl)}
 63	    value={getName(drPolicyControlState?.drPlacementControl)}
 64	    isChecked={isValid}
 65	    isDisabled={!isValid}
 66	    data-test={`option-${getName(drPolicyControlState?.drPlacementControl)}`}
 67	  >
 68	    {drPolicyControlState?.subscriptions.map((subName) => (
 69	      <p key={subName}> {subName} </p>
 70	    ))}
 71	    <HelperText>
 72	      <HelperTextItem variant={isValid ? 'default' : 'indeterminate'}>
 73	        {t('Placed: {{cluster}}', {
 74	          cluster: drPolicyControlState?.clusterName,
 75	        })}
 76	      </HelperTextItem>
 77	    </HelperText>
 78	  </SelectOption>
 79	);
 80	
 81	export const SubscriptionGroupSelector: React.FC<
 82	  SubscriptionGroupSelectorProps
 83	> = ({ state, dispatch }) => {
 84	  const { t } = useCustomTranslation();
 85	  const { selectedTargetCluster, selectedDRPolicy, actionType } = state;
 86	  const [options, setOptions] = React.useState<React.ReactElement[]>([]);
 87	  const memoizedDRPCState = useDeepCompareMemoize(
 88	    state.drPolicyControlState,
 89	    true
 90	  );
 91	
 92	  const setSelected = React.useCallback(
 93	    (selection: string[], isUpdate?: boolean) => {
 94	      dispatch({
 95	        type: FailoverAndRelocateType.SET_SELECTED_SUBS_GROUP,
 96	        payload: {
 97	          selected: selection,
 98	          isUpdate,
 99	        },
100	      });
101	    },
102	    [dispatch]
103	  );
104	
105	  const setErrorMessage = React.useCallback(
106	    (errorMessage: ErrorMessageType) => {
107	      dispatch({
108	        type: FailoverAndRelocateType.SET_ERROR_MESSAGE,
109	        payload: {
110	          subscriptionGroupErrorMessage: errorMessage,
111	        },
112	      });
113	    },
114	    [dispatch]
115	  );
116	
117	  React.useEffect(() => {
118	    // Filter all DRPlacements under a selected target cluster
119	    if (
120	      !!Object.keys(selectedTargetCluster).length &&
121	      selectedTargetCluster?.isClusterAvailable
122	    ) {
123	      const validState: string[] = [];
124	      const generatedOptions = memoizedDRPCState.reduce(
125	        (acc, drpcState) => {
126	          if (validateDRPolicy(drpcState, selectedDRPolicy?.policyName)) {
127	            const isValidTargetCluster = validateTargetCluster(
128	              drpcState,
129	              selectedTargetCluster?.clusterInfo
130	            );
131	            const isDRActionReady = checkDRActionReadiness(
132	              drpcState?.drPlacementControl,
133	              actionType
134	            );
135	            isValidTargetCluster &&
136	              isDRActionReady &&
137	              validState.push(getName(drpcState.drPlacementControl));
138	            const option = getOptions(drpcState, isValidTargetCluster, t);
139	            return {
140	              validOptions: getValidOptions(
141	                option,
142	                acc.validOptions,
143	                isValidTargetCluster,
144	                isDRActionReady
145	              ),
146	              inValidOptions: getInValidOptions(
147	                option,
148	                acc.inValidOptions,
149	                isValidTargetCluster
150	              ),
151	            };
152	          } else {
153	            return acc;
154	          }
155	        },
156	        {
157	          validOptions: [],
158	          inValidOptions: [],
159	        }
160	      );
161	      if (
162	        !!generatedOptions.validOptions.length ||
163	        !!generatedOptions.inValidOptions.length
164	      ) {
165	        setSelected(validState);
166	        setOptions([
167	          ...generatedOptions.validOptions,
168	          ...generatedOptions.inValidOptions,
169	        ]);
170	        setErrorMessage(0 as ErrorMessageType);
171	      } else {
172	        setOptions([]);
173	        setSelected([]);
174	        setErrorMessage(ErrorMessageType.NO_SUBSCRIPTION_GROUP_FOUND);
175	      }
176	    } else {
177	      setSelected([]);
178	      setOptions([]);
179	    }
180	  }, [
181	    actionType,
182	    memoizedDRPCState,
183	    selectedDRPolicy,
184	    selectedTargetCluster,
185	    dispatch,
186	    setSelected,
187	    setErrorMessage,
188	    setOptions,
189	    t,
190	  ]);
191	
192	  const onSelect = (_, selection) =>
193	    state.selectedSubsGroups.includes(selection)
194	      ? setSelected(
195	          state.selectedSubsGroups.filter((item) => item !== selection)
196	        )
197	      : setSelected([selection], true);
198	
199	  const clearSelection = () => {
200	    setSelected([]);
201	  };
202	
203	  return (
204	    <>
205	      <MultiSelectDropdown
206	        variant={'checkbox'}
207	        placeholderText={
208	          options?.length > 0
209	            ? t('{{selected}} of {{total}} selected', {
210	                selected: state.selectedSubsGroups.length,
211	                total: options?.length,
212	              })
213	            : t('Select')
214	        }
215	        isDisabled={
216	          !options?.length ||
217	          state.modalFooterStatus === ModalFooterStatus.FINISHED
218	        }
219	        onChange={onSelect}
220	        selections={state.selectedSubsGroups}
221	        aria-label={t('subscription-selector')}
222	        data-test="subs-group-selector-options"
223	        selectOptions={options}
224	        onClear={clearSelection}
225	      />
226	      <HelperText>
227	        <HelperTextItem variant="indeterminate">
228	          {t('Select the subscriptions groups you wish to replicate via')}
229	        </HelperTextItem>
230	      </HelperText>
231	    </>
232	  );
233	};
234	
235	type SubscriptionGroupSelectorProps = {
236	  state: FailoverAndRelocateState;
237	  dispatch: React.Dispatch<FailoverAndRelocateAction>;
238	};

