  1	import * as React from 'react';
  2	import TimesIcon from '@patternfly/react-icons/dist/esm/icons/times-icon';
  3	import {
  4	  Select,
  5	  SelectOption,
  6	  SelectList,
  7	  MenuToggle,
  8	  MenuToggleElement,
  9	  TextInputGroup,
 10	  TextInputGroupMain,
 11	  TextInputGroupUtilities,
 12	  Button,
 13	  SelectProps,
 14	  MenuToggleStatus,
 15	  ChipGroup,
 16	  Chip,
 17	} from '@patternfly/react-core';
 18	import { useCustomTranslation } from '../useCustomTranslationHook';
 19	import './multiselectdropdown.scss';
 20	
 21	export type MultiSelectDropdownProps = Omit<
 22	  SelectProps,
 23	  'onChange' | 'onToggle' | 'toggle'
 24	> & {
 25	  id?: string;
 26	  className?: string;
 27	  selections?: string[];
 28	  selectOptions: JSX.Element[];
 29	  placeholderText?: string;
 30	  onChange: (selected: string[], selection?: string) => void;
 31	  validated?: 'success' | 'warning' | 'error' | 'default';
 32	  isCreatable?: boolean;
 33	  isDisabled?: boolean;
 34	  variant?: 'typeahead' | 'checkbox';
 35	  popperProps?: SelectProps['popperProps'];
 36	  hasInlineFilter?: boolean;
 37	  onClear?: () => void;
 38	  'aria-label'?: string;
 39	  'data-test'?: string;
 40	};
 41	
 42	type Option = {
 43	  value: string;
 44	  key: string;
 45	  label: React.ReactNode;
 46	  description?: React.ReactNode;
 47	};
 48	
 49	export const MultiSelectDropdown: React.FC<MultiSelectDropdownProps> = ({
 50	  id,
 51	  className,
 52	  selections = [],
 53	  selectOptions,
 54	  placeholderText = 'Select options',
 55	  onChange,
 56	  validated,
 57	  isCreatable = false,
 58	  isDisabled,
 59	  variant = 'typeahead',
 60	  popperProps,
 61	  hasInlineFilter,
 62	  onClear,
 63	  ...props
 64	}) => {
 65	  const { t } = useCustomTranslation();
 66	  const [isOpen, setIsOpen] = React.useState(false);
 67	  const [filterValue, setFilterValue] = React.useState('');
 68	  const [createdOptions, setCreatedOptions] = React.useState<Option[]>([]);
 69	  const [status, setStatus] = React.useState<MenuToggleStatus>();
 70	  const [newOptionVal, setNewOptionVal] = React.useState('');
 71	  const textInputRef = React.useRef<HTMLInputElement>(null);
 72	  const DISABLED = '__disabled__';
 73	
 74	  const baseOptions = React.useMemo<Option[]>(() => {
 75	    return selectOptions.map((opt) => ({
 76	      value: String(opt.props.value ?? opt.props.children),
 77	      key: String(opt.key ?? opt.props.children),
 78	      label: opt.props.children,
 79	      description: opt.props.description,
 80	    }));
 81	  }, [selectOptions]);
 82	
 83	  const fullOptions = React.useMemo(
 84	    () => [...baseOptions, ...createdOptions],
 85	    [baseOptions, createdOptions]
 86	  );
 87	
 88	  React.useEffect(() => {
 89	    if (filterValue) {
 90	      setNewOptionVal(filterValue);
 91	    }
 92	  }, [filterValue]);
 93	
 94	  const visibleOptions = React.useMemo(() => {
 95	    let filteredOptions = fullOptions;
 96	    const lowerValue = filterValue.toLowerCase();
 97	    if (hasInlineFilter && filterValue) {
 98	      filteredOptions = fullOptions.filter((opt) =>
 99	        String(opt.label).toLowerCase().includes(lowerValue)
100	      );
101	
102	      const exactMatchExists = fullOptions.some(
103	        (opt) => opt.value.toLowerCase() === lowerValue
104	      );
105	
106	      if (filteredOptions.length === 0 && isCreatable) {
107	        return [
108	          {
109	            value: filterValue,
110	            key: filterValue,
111	            label: `Create "${filterValue}"`,
112	          },
113	        ];
114	      }
115	
116	      if (isCreatable && !exactMatchExists) {
117	        return [
118	          {
119	            value: filterValue,
120	            key: filterValue,
121	            label: `Create "${filterValue}"`,
122	          },
123	          ...filteredOptions,
124	        ];
125	      }
126	    }
127	
128	    return filteredOptions;
129	  }, [fullOptions, filterValue, isCreatable, hasInlineFilter]);
130	
131	  React.useEffect(() => {
132	    let derivedValidated = validated === 'error' ? 'danger' : validated;
133	    setStatus(
134	      derivedValidated && derivedValidated !== 'default'
135	        ? (derivedValidated as MenuToggleStatus)
136	        : undefined
137	    );
138	  }, [validated]);
139	
140	  const onSelect = (
141	    _event: React.MouseEvent | React.ChangeEvent,
142	    value: string
143	  ) => {
144	    let newSelections = [...selections];
145	    const createVal = newOptionVal;
146	
147	    if (value === createVal) {
148	      if (!createVal) return;
149	
150	      if (
151	        !fullOptions.some(
152	          (o) => o.value.toLowerCase() === createVal.toLowerCase()
153	        )
154	      ) {
155	        setCreatedOptions((prev) => [
156	          ...prev,
157	          { value: createVal, key: createVal, label: createVal },
158	        ]);
159	      }
160	
161	      newSelections = selections.includes(createVal)
162	        ? selections.filter((s) => s !== createVal)
163	        : [...selections, createVal];
164	
165	      setFilterValue('');
166	    } else {
167	      newSelections = selections.includes(value)
168	        ? selections.filter((s) => s !== value)
169	        : [...selections, value];
170	    }
171	
172	    onChange(newSelections, value);
173	  };
174	
175	  const onInputChange = (
176	    _e: React.FormEvent<HTMLInputElement>,
177	    val: string
178	  ) => {
179	    setFilterValue(val);
180	    if (val && !isOpen) setIsOpen(true);
181	  };
