 79	export const SubscriptionGroupSelector: React.FC<
 80	  SubscriptionGroupSelectorProps
 81	> = ({ state, dispatch }) => {
 82	  const { t } = useCustomTranslation();
 83	  const { selectedTargetCluster, selectedDRPolicy, actionType } = state;
 84	  const [options, setOptions] = React.useState<React.ReactElement[]>([]);
 85	  const memoizedDRPCState = useDeepCompareMemoize(
 86	    state.drPolicyControlState,
 87	    true
 88	  );
 89	
 90	  const setSelected = React.useCallback(
 91	    (selection: string[], isUpdate?: boolean) => {
 92	      dispatch({
 93	        type: FailoverAndRelocateType.SET_SELECTED_SUBS_GROUP,
 94	        payload: {
 95	          selected: selection,
 96	          isUpdate,
 97	        },
 98	      });
 99	    },
100	    [dispatch]
101	  );
102	
103	  const setErrorMessage = React.useCallback(
104	    (errorMessage: ErrorMessageType) => {
105	      dispatch({
106	        type: FailoverAndRelocateType.SET_ERROR_MESSAGE,
107	        payload: {
108	          subscriptionGroupErrorMessage: errorMessage,
109	        },
110	      });
111	    },
112	    [dispatch]
113	  );
114	
115	  React.useEffect(() => {
116	    // Filter all DRPlacements under a selected target cluster
117	    if (
118	      !!Object.keys(selectedTargetCluster).length &&
119	      selectedTargetCluster?.isClusterAvailable
120	    ) {
121	      const validState: string[] = [];
122	      const generatedOptions = memoizedDRPCState.reduce(
123	        (acc, drpcState) => {
124	          if (validateDRPolicy(drpcState, selectedDRPolicy?.policyName)) {
125	            const isValidTargetCluster = validateTargetCluster(
126	              drpcState,
127	              selectedTargetCluster?.clusterInfo
128	            );
129	            const isDRActionReady = checkDRActionReadiness(
130	              drpcState?.drPlacementControl,
131	              actionType
132	            );
133	            isValidTargetCluster &&
134	              isDRActionReady &&
135	              validState.push(getName(drpcState.drPlacementControl));
136	            const option = getOptions(drpcState, isValidTargetCluster, t);
137	            return {
138	              validOptions: getValidOptions(
139	                option,
140	                acc.validOptions,
141	                isValidTargetCluster,
142	                isDRActionReady
143	              ),
144	              inValidOptions: getInValidOptions(
145	                option,
146	                acc.inValidOptions,
147	                isValidTargetCluster
148	              ),
149	            };
150	          } else {
151	            return acc;
152	          }
153	        },
154	        {
155	          validOptions: [],
156	          inValidOptions: [],
157	        }
158	      );
159	      if (
160	        !!generatedOptions.validOptions.length ||
161	        !!generatedOptions.inValidOptions.length
162	      ) {
163	        setSelected(validState);
164	        setOptions([
165	          ...generatedOptions.validOptions,
166	          ...generatedOptions.inValidOptions,
167	        ]);
168	        setErrorMessage(0 as ErrorMessageType);
169	      } else {
170	        setOptions([]);
171	        setSelected([]);
172	        setErrorMessage(ErrorMessageType.NO_SUBSCRIPTION_GROUP_FOUND);
173	      }
174	    } else {
175	      setSelected([]);
176	      setOptions([]);
177	    }
178	  }, [
179	    actionType,
180	    memoizedDRPCState,
181	    selectedDRPolicy,
182	    selectedTargetCluster,
183	    dispatch,
184	    setSelected,
185	    setErrorMessage,
186	    setOptions,
187	    t,
188	  ]);
189	
190	  const onSelect = (_, selection) =>
191	    state.selectedSubsGroups.includes(selection)
192	      ? setSelected(
193	          state.selectedSubsGroups.filter((item) => item !== selection)
194	        )
195	      : setSelected([selection], true);
196	
197	  const clearSelection = () => {
198	    setSelected([]);
199	  };
200	
201	  return (
202	    <>
203	      <MultiSelectDropdown
204	        variant={'checkbox'}
205	        placeholderText={
206	          options?.length > 0
207	            ? t('{{selected}} of {{total}} selected', {
208	                selected: state.selectedSubsGroups.length,
209	                total: options?.length,
210	              })
211	            : t('Select')
212	        }
213	        isDisabled={
214	          !options?.length ||
215	          state.modalFooterStatus === ModalFooterStatus.FINISHED
216	        }
217	        onChange={onSelect}
218	        selections={state.selectedSubsGroups}
219	        aria-label={t('subscription-selector')}
220	        data-test="subs-group-selector-options"
221	        selectOptions={options}
222	        onClear={clearSelection}
223	      />
224	      <HelperText>
225	        <HelperTextItem variant="indeterminate">
226	          {t('Select the subscriptions groups you wish to replicate via')}
227	        </HelperTextItem>
228	      </HelperText>
229	    </>
230	  );
231	};
